/* This is a CSS comment */

/* Style the body (entire page) */
body {
  font-family: Arial, sans-serif;
  background-color: #f4f4f4;
  color: #333333;
  margin: 0;
  padding: 0;
}

/* Style all h1 headings */
h1 {
  font-size: 2rem;
  color: #0056b3;
  text-align: center;
}

/* Style paragraphs */
p {
  font-size: 1rem;
  line-height: 1.6;
  margin-bottom: 16px;
}

/* Style the navigation links */
nav a {
  color: white;
  text-decoration: none;
  padding: 8px 16px;
  background-color: #0056b3;
  border-radius: 4px;
  margin-right: 8px;
}

/* Change appearance when mouse hovers over a link */
nav a:hover {
  background-color: #003d82;
}

/* Default styles — applied on ALL screen sizes (mobile first) */
.container {
  width: 100%;        /* Full width on small screens */
  padding: 10px;
}

.card {
  width: 100%;        /* Each card takes full width on mobile */
  margin-bottom: 16px;
}

nav {
  display: flex;
  flex-direction: column;   /* Navigation stacks vertically on mobile */
}

/* Tablet — screens wider than 768px */
@media (min-width: 768px) {
  .container {
    max-width: 720px;
    margin: 0 auto;         /* Centre the container */
  }

  .card {
    width: 48%;             /* Two cards side by side on tablet */
    display: inline-block;
  }

  nav {
    flex-direction: row;    /* Navigation goes horizontal on tablet */
  }
}

/* Desktop — screens wider than 1024px */
@media (min-width: 1024px) {
  .container {
    max-width: 960px;
  }

  .card {
    width: 30%;             /* Three cards in a row on desktop */
  }
}
